using System.Collections;

/// <summary>
/// Regista um NPC como resgatado nesta área (PlayerProgress.AddNpcRescued) e
/// actualiza automaticamente a população da vila do mundo correspondente em
/// WorldState (dispara WorldState.VillagePopulationChanged — HUD, música,
/// lojas e decoração reagem automaticamente se estiverem subscritos).
///
/// A operação é idempotente quando "npcId" está preenchido: chamar o evento
/// duas vezes (por erro, repetição de diálogo ou duplicação de configuração)
/// não incrementa a contagem nem dispara eventos novamente.
///
/// A variável global "NpcResgatado_&lt;npcId&gt;" é criada automaticamente em
/// GameVariables — permite usar Condition_BoolVariable para verificar o
/// resgate sem configurar Action_SetBoolVariable manualmente.
///
/// Usar nos eventos de NPC de "resgate concluído", antes de Action_Autosave.
/// O validador do Editor avisa se Action_Autosave estiver em falta.
/// </summary>
[System.Serializable]
public class Action_RescueNpc : NpcAction
{
    [Tooltip("Identificador único deste NPC (ex: \"aldeao_maia\"). Quando preenchido, a operação é idempotente e a variável global NpcResgatado_<npcId> é criada automaticamente. Deixar vazio apenas se não houver ID configurado (comportamento antigo sem idempotência).")]
    public string npcId;

    [Tooltip("Área onde este NPC foi resgatado (AreaData). Necessário para contabilizar o resgate e calcular a população da vila do mundo desta área.")]
    public AreaData area;

    [Tooltip("Este resgate conta para a população/restauração da vila? Desactivar para NPCs de evento ou viajantes que não devem contar para os 100% da vila.")]
    public bool countsForVillageRestoration = true;

    public override IEnumerator Execute(NpcController npc)
    {
        if (area == null || !countsForVillageRestoration) yield break;

        PlayerProgress.Instance?.AddNpcRescued(area, npcId);
        yield break;
    }
}

/// <summary>
/// Soma 1 ao "current" da população de uma vila directamente em WorldState,
/// SEM passar por PlayerProgress.AddNpcRescued. Útil para NPCs que aparecem
/// na vila sem serem "resgatados" oficialmente (ex: lojistas que chegam por
/// missão, visitantes temporários, NPCs de evento).
///
/// Respeita o limite "max": se current já for igual a max (e max > 0), não
/// soma. O max deve ter sido definido previamente via Action_SetVillagePopulation
/// ou pelo sistema de sincronização automática (SyncAllVillagePopulations).
///
/// Dispara WorldState.VillagePopulationChanged — reage automaticamente em
/// HUD, BGM da vila, lojas e decoração.
/// </summary>
[System.Serializable]
public class Action_AddVillagePopulation : NpcAction
{
    [Tooltip("ID da vila a actualizar (WorldData.mainVillageId). Se vazio, usa a vila do mundo actual (WorldState.CurrentWorld.mainVillageId).")]
    public string villageId;

    public override IEnumerator Execute(NpcController npc)
    {
        string vid = string.IsNullOrEmpty(villageId)
            ? WorldState.Instance?.CurrentWorld?.mainVillageId
            : villageId;

        if (!string.IsNullOrEmpty(vid))
            WorldState.Instance?.AddVillagePopulation(vid);

        yield break;
    }
}

/// <summary>
/// Define directamente o "current" e o "max" da população de uma vila em
/// WorldState. Útil para:
///   • Inicializar o max no arranque da cena da vila.
///   • Forçar um valor específico (ex: cinematica que move vários NPCs de uma vez).
///   • Reduzir a população (ex: NPC que abandona a vila).
///
/// Dispara WorldState.VillagePopulationChanged.
/// </summary>
[System.Serializable]
public class Action_SetVillagePopulation : NpcAction
{
    [Tooltip("ID da vila a actualizar (WorldData.mainVillageId). Se vazio, usa a vila do mundo actual.")]
    public string villageId;

    [Tooltip("Número actual de habitantes.")]
    [UnityEngine.Min(0)] public int current;

    [Tooltip("Capacidade máxima da vila. 0 = sem limite.")]
    [UnityEngine.Min(0)] public int max;

    public override IEnumerator Execute(NpcController npc)
    {
        string vid = string.IsNullOrEmpty(villageId)
            ? WorldState.Instance?.CurrentWorld?.mainVillageId
            : villageId;

        if (!string.IsNullOrEmpty(vid))
            WorldState.Instance?.SetVillagePopulation(vid, current, max);

        yield break;
    }
}

/// <summary>
/// Força a re-sincronização da população de um mundo a partir dos resgates
/// registados em PlayerProgress. Equivalente a chamar
/// PlayerProgress.SyncVillagePopulationForWorld(world) — útil depois de
/// carregar um save antigo ou depois de operações em lote que alteraram
/// vários contadores de NPCs sem disparar AddNpcRescued.
/// </summary>
[System.Serializable]
public class Action_SyncVillagePopulation : NpcAction
{
    [Tooltip("Mundo cujos resgates de NPC são somados e aplicados à sua vila principal. Se vazio, usa o mundo actual.")]
    public WorldData world;

    public override IEnumerator Execute(NpcController npc)
    {
        WorldData w = world != null ? world : WorldState.Instance?.CurrentWorld;
        PlayerProgress.Instance?.SyncVillagePopulationForWorld(w);
        yield break;
    }
}
